    private static (string Sql, Dictionary<string, object> Parameters) BuildSecureQuery(
        string tableName, 
        Dictionary<string, string> filters, 
        string orderBy, 
        string limit)
    {
        var parameters = new Dictionary<string, object>();
        var whereClause = new StringBuilder();
        var paramCounter = 0;

        var allowedColumns = GetAllowedColumnsForTable(tableName);

        foreach (var filter in filters)
        {
            if (!allowedColumns.Contains(filter.Key))
            {
                continue;
            }

            if (whereClause.Length > 0)
            {
                whereClause.Append(" AND ");
            }

            var paramName = $"@param{paramCounter++}";
            var columnName = SanitizeColumnName(filter.Key);

            if (filter.Value.Contains("%") || filter.Value.Contains("*"))
            {
                whereClause.Append($"[{columnName}] LIKE {paramName}");
                parameters[paramName] = filter.Value.Replace("*", "%");
            }
            else if (filter.Value.StartsWith(">") || filter.Value.StartsWith("<"))
            {
                var op = filter.Value.Substring(0, 1);
                var value = filter.Value.Substring(1);
                whereClause.Append($"[{columnName}] {op} {paramName}");
                parameters[paramName] = ParseValue(value);
            }
            else if (filter.Value.Contains(","))
            {
                var values = filter.Value.Split(',');
                var inParams = new List<string>();
                foreach (var val in values)
                {
                    var inParamName = $"@param{paramCounter++}";
                    inParams.Add(inParamName);
                    parameters[inParamName] = val.Trim();
                }
                whereClause.Append($"[{columnName}] IN ({string.Join(", ", inParams)})");
            }
            else
            {
                whereClause.Append($"[{columnName}] = {paramName}");
                parameters[paramName] = filter.Value;
            }
        }

        var sql = new StringBuilder($"SELECT * FROM [{SanitizeTableName(tableName)}]");

        if (whereClause.Length > 0)
        {
            sql.Append($" WHERE {whereClause}");
        }

        if (!string.IsNullOrEmpty(orderBy) && allowedColumns.Contains(orderBy.TrimEnd('-')))
        {
            var isDesc = orderBy.EndsWith("-");
            var orderColumn = SanitizeColumnName(orderBy.TrimEnd('-'));
            sql.Append($" ORDER BY [{orderColumn}] {(isDesc ? "DESC" : "ASC")}");
        }

        if (!string.IsNullOrEmpty(limit) && int.TryParse(limit, out int limitValue) && limitValue > 0 && limitValue <= 1000)
